@@ -1238,13 +1238,22 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
   const APInt *MaskC;
   ICmpInst::Predicate Pred;
+  Value *CmpRHS;
   if (!match(Add.getOperand(1),
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_Value(CmpRHS)))))
     return nullptr;
-
+  
   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
+  // Check for canonical ugt pattern: (X & Mask) >u SMin where Mask = SMin | (DivC - 1)
+  bool IsCanonical = (Pred == ICmpInst::ICMP_UGT && match(CmpRHS, m_SignMask()));
+  // Check for alternative eq pattern: (X & Mask) == Mask where Mask = SMin | 1 (only for DivC == 2)
+  // Check for alternative eq pattern: (X & Mask) == Mask where Mask = SMin | 1 (only for DivC == 2)
+  bool IsEqPattern = (Pred == ICmpInst::ICMP_EQ && *DivC == 2 &&
+                      match(CmpRHS, m_SpecificInt(*MaskC)));
+  if (!IsCanonical && !IsEqPattern)
+    return nullptr;
+  
   if (*MaskC != (SMin | (*DivC - 1)))
     return nullptr;

