def sdiv(a, b):
    return int(a / b)

def ashr(a, shift, bits=8):
    a = a & ((1 << bits) - 1)
    if a >= (1 << (bits-1)):
        a = a - (1 << bits)
    result = a >> shift
    return result & ((1 << bits) - 1)

print('Testing formula vs ashr:')
all_match = True
for a in range(-128, 128):
    s = sdiv(a, 2)
    cond = ((a & 0x81) == 0x81)
    adj = -1 if cond else 0
    result = (s + adj) & 0xFF
    result_s = result if result < 128 else result - 256
    ash = ashr(a, 1)
    ash_s = ash if ash < 128 else ash - 256
    if result_s != ash_s:
        print(f'{a:4d}: formula={result_s}, ashr={ash_s}')
        all_match = False

print('All match!' if all_match else 'Mismatches found')
